function BloomMascot({ height = 180, fill }) {
  const [blinking, setBlinking] = useState(false);
  const [itemIdx, setItemIdx] = useState(0);
  const [itemFading, setItemFading] = useState(false);
  const [mouthO, setMouthO] = useState(false);
  useEffect(() => {
    const blink = () => { setBlinking(true); setTimeout(() => setBlinking(false), 150); };
    const interval = setInterval(blink, 3000 + Math.random() * 1500);
    return () => clearInterval(interval);
  }, []);
  useEffect(() => {
    const interval = setInterval(() => {
      setItemFading(true); setMouthO(true);
      setTimeout(() => { setItemIdx(i => (i + 1) % MI.length); setItemFading(false); setTimeout(() => setMouthO(false), 600); }, 300);
    }, 2500);
    return () => clearInterval(interval);
  }, []);
  const abs = { position: "absolute", top: 0, left: 0, width: "100%", height: "100%", pointerEvents: "none" };
  return (
    <div style={{ position: "relative", width: fill ? "100%" : height, height: fill ? "100%" : height, aspectRatio: "1", animation: "mascotFloat 3s ease-in-out infinite" }}>
      <img src={ML.neck} alt="" style={abs} />
      <div style={{ ...abs, transformOrigin: "45% 85%", animation: "headTilt 4s ease-in-out infinite" }}>
        <img src={ML.flower} alt="" style={abs} />
        <img src={blinking ? ML.eyesClosed : ML.eyesOpen} alt="" style={abs} />
        <img src={mouthO ? ML.mouthOpen : ML.mouthClosed} alt="" style={abs} />
      </div>
      <img src={MI[itemIdx].src} alt="" style={{ ...abs, opacity: itemFading ? 0 : 1, transform: itemFading ? "scale(0.7)" : "scale(1)", transition: "all 0.3s ease" }} />
      <div style={{ position: "absolute", bottom: -18, left: 0, width: "100%", textAlign: "center", fontFamily: "'JetBrains Mono',monospace", fontSize: 12, fontWeight: 600, color: "#5B2FE6", opacity: itemFading ? 0 : 1, transition: "opacity 0.3s ease" }}>
        {MI[itemIdx].label}
      </div>
    </div>
  );
}

