// ── SCAN ANIMATION ──
function ScanSequence({ onComplete }) {
  const [step, setStep] = useState(0);
  const msgs = ["Reading game code...", "Mapping player journey...", "Checking algorithm signals...", "Calculating revenue gap...", "Analysis complete."];
  useEffect(() => {
    if (step < msgs.length) {
      const t = setTimeout(() => setStep(s => s + 1), step === msgs.length - 1 ? 500 : 700);
      return () => clearTimeout(t);
    } else { onComplete?.(); }
  }, [step]);

  return (
    <div style={{ padding: "16px 24px", borderRadius: 14, background: T.surface, border: `1px solid ${T.border}`, marginBottom: 24 }}>
      <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 12 }}>
        <div style={{ width: 28, height: 28, borderRadius: 7, background: "linear-gradient(135deg,#1a3a25,#0a2018)", overflow: "hidden" }}><img src="data:image/jpeg;base64," style={{ width: "100%", height: "100%", objectFit: "cover" }} /></div>
        <span style={{ fontSize: 13, fontWeight: 700 }}>Analyzing Fish a Brainrot...</span>
      </div>
      {msgs.map((m, i) => (
        <div key={i} style={{
          fontSize: 12, fontFamily: ff.m, marginBottom: 4,
          color: i < step ? T.green : i === step ? T.text : T.textTer,
          opacity: i <= step ? 1 : 0.3, transition: "all 0.3s ease",
          display: "flex", alignItems: "center", gap: 8,
        }}>
          <span style={{ fontSize: 10, width: 14, textAlign: "center" }}>{i < step ? "✓" : i === step ? "⟳" : "○"}</span>
          {m}
        </div>
      ))}
      {/* Progress bar */}
      <div style={{ height: 3, borderRadius: 2, background: T.border, marginTop: 10, overflow: "hidden" }}>
        <div style={{ height: "100%", borderRadius: 2, background: T.green, width: `${(step / msgs.length) * 100}%`, transition: "width 0.5s ease" }} />
      </div>
    </div>
  );
}

